import{j as e}from"./jsx-runtime.TBa3i5EZ.js";import{C as o}from"./camera.DxdKtQLf.js";import"./index.CVf8TyFT.js";import"./createLucideIcon.Dyt5LH96.js";const i=[{id:"realidad-virtual",titulo:"Realidad Virtual para proteger la naturaleza",texto:"Los murciélagos viven en cuevas y espacios naturales que no pueden recibir visitas masivas sin sufrir daños irreversibles. El turismo convencional fragmenta hábitats, genera contaminación lumínica y presiona sobre espacios protegidos. MUMA resuelve este problema llevando la cueva a las personas en lugar de llevar a las personas a la cueva. Han escaneado en 3D cuevas reales, grabado ultrasonidos auténticos de especies ibéricas y construido un entorno virtual donde el usuario explora, aprende y siente sin generar ningún impacto ecológico. La MuMa Bat Cave Experience VR ya ha sido vivida por más de 700 personas en 2025 en entornos tan distintos como una cueva en Portugal, un centro comercial en Málaga y una reserva natural protegida. Museos, hoteles, centros educativos y ayuntamientos pueden contratar esta experiencia como licencia B2B de forma recurrente.",invertido:!1},{id:"educacion-ambiental",titulo:"Educación ambiental que conecta emocionalmente",texto:"La educación ambiental tradicional informa, pero raramente transforma. MUMA parte de una convicción diferente: la experiencia directa cambia comportamientos donde el discurso no llega. Por eso combinan detectores de ultrasonidos en tiempo real, talleres participativos, dinámicas de grupo y realidad virtual en una misma sesión. El visitante escucha al murciélago en vuelo, lo observa en su hábitat natural a través de las gafas VR y comprende de primera mano por qué su desaparición afecta directamente a nuestra alimentación, nuestra salud y nuestra economía. Las actividades se adaptan al nivel educativo de cada grupo y pueden integrarse en el currículo escolar o en proyectos municipales de sostenibilidad. Centros educativos, AMPAs, museos de ciencia natural, institutos y ayuntamientos de toda la Costa del Sol ya han pasado por estas experiencias.",invertido:!0},{id:"refugios",titulo:"Refugios artesanales: la solución más ecológica contra las plagas",texto:"Un solo murciélago pequeño puede eliminar entre 1.000 y 3.000 insectos por noche. Eso significa que una colonia de 50 individuos puede eliminar hasta 150.000 mosquitos en una sola noche, sin pesticidas, sin costes recurrentes y sin efectos secundarios sobre el ecosistema. MUMA fabrica sus propios refugios de forma artesanal en Málaga usando madera de alta calidad resistente a la humedad y los rayos UV, técnicas de impresión 3D y materiales biodegradables y compostables. Cada refugio tiene diseño de doble cámara con superficies interiores rayadas para que los murciélagos se sujeten con comodidad, y se georreferencia y numera para permitir un seguimiento científico personalizado a lo largo del tiempo. Los refugios comerciales de bajo coste no ofrecen ventilación adecuada, usan clavos que pueden herir a los animales y se deterioran en pocos meses. Los de MUMA están diseñados para durar décadas y generar un impacto real y medible en la reducción de plagas.",invertido:!1},{id:"consultoria",titulo:"Consultoría medioambiental y bioacústica avanzada",texto:"La monitorización de fauna nocturna requiere tecnología especializada y conocimiento científico profundo. MUMA ofrece consultoría medioambiental basada en bioacústica: el análisis de los ultrasonidos que emiten los murciélagos para detectar su presencia, identificar especies y evaluar el estado de las poblaciones en un territorio concreto. Este servicio es esencial para estudios de impacto ambiental, proyectos de restauración ecológica y cumplimiento de normativa medioambiental. Han trabajado con la Junta de Andalucía, la Diputación Provincial de Málaga, la Fundación Cueva de Nerja, Selwo Aventura, el Parque Tecnológico de Málaga y SECEMU, entre otros. Su equipo combina formación técnica en gestión forestal y medio natural con años de trabajo de campo en ecosistemas urbanos, agroforestales y de alta montaña.",invertido:!0},{id:"bat-nights",titulo:"Bat Nights: cuando la ciencia se convierte en experiencia",texto:"Las Bat Nights son la demostración más tangible de que conservación y divulgación pueden ir de la mano sin renunciar al rigor científico. Son eventos nocturnos que combinan detección de ultrasonidos en tiempo real, la experiencia VR MuMa Bat Cave Experience, charlas científicas, exposiciones fotográficas y talleres educativos. Se han celebrado ya en cuatro escenarios completamente distintos: las Grutas da Moeda en Portugal con más de 200 visitantes en un solo día, la Cueva de Nerja donde el éxito del evento llevó directamente a la instalación de refugios monitorizados en el entorno, Plaza Mayor Málaga donde demostraron que el modelo funciona en entornos urbanos comerciales con 200 a 300 participantes en dos días, y la Laguna de Fuente de Piedra, reserva natural protegida, donde se combinó interpretación ambiental in situ con realidad virtual para familias y escolares. El formato es escalable, adaptable a cualquier espacio y replicable internacionalmente.",invertido:!1},{id:"control-plagas",titulo:"Control biológico de plagas basado en la naturaleza",texto:"El uso de pesticidas en España genera un coste económico y ambiental enorme. Se estima que los murciélagos evitan gastos de entre 1 y 10 millones de euros anuales solo en España gracias a su actividad como controladores naturales de insectos. MUMA instala redes de refugios monitorizados en campos de golf, hoteles y resorts, fincas agrícolas, campings y municipios para crear ecosistemas donde los murciélagos controlan de forma natural las poblaciones de mosquito tigre, mosca del olivo, polilla del racimo, procesionaria del pino y mosquito verde de la vid. Además del murciélago, trabajan con otras especies de fauna auxiliar como cernícalos, mochuelos, mariposas y salamanquesas. Es una solución 100% ecológica, con impacto económico medible, aval científico institucional y seguimiento técnico incluido en cada instalación.",invertido:!0}];function s(){return e.jsxs("div",{className:"bg-fondo-superficie border border-white/5 rounded-2xl h-72 flex flex-col items-center justify-center gap-3",children:[e.jsx(o,{size:36,className:"text-marca-principal/30","aria-hidden":"true"}),e.jsx("span",{className:"text-texto-secundario/40 text-xs",children:"Imagen próximamente"})]})}function n({bloque:a}){return e.jsxs("div",{className:"grid grid-cols-1 md:grid-cols-2 gap-12 items-center",children:[e.jsxs("div",{className:a.invertido?"md:order-2":"md:order-1",children:[e.jsx("h3",{className:"text-2xl sm:text-3xl font-bold text-texto-titulo mb-5 leading-snug",children:a.titulo}),e.jsx("p",{className:"text-texto-secundario leading-relaxed",children:a.texto})]}),e.jsx("div",{className:a.invertido?"md:order-1":"md:order-2",children:e.jsx(s,{})})]})}const r=[{nombre:"La Opinión de Málaga",href:"https://www.laopiniondemalaga.es/malaga/2025/07/10/selwo-aventura-murcielagos-malaga-unen-119552762.html"},{nombre:"Málaga Hoy",href:"https://www.malagahoy.es/malaga/murcielagos-aliados-mosquitos-virus-nilo-malaga_0_2005367409.html"},{nombre:"El Español",href:"https://www.elespanol.com/malaga/economia/tecnologia/20231230/cueva-realidad-virtual-hara-entender-hacen-murcielagos/819168532_0.html"},{nombre:"Andalucía Lab",href:"https://mumabatcompany.com/"},{nombre:"Hola Andalucía",href:"https://mumabatcompany.com/"},{nombre:"Canal Málaga",href:"https://www.canalmalaga.es/"}];function m(){return e.jsxs(e.Fragment,{children:[e.jsx("section",{id:"que-hacemos",className:"bg-fondo-base py-20 px-8 sm:px-12",children:e.jsxs("div",{className:"max-w-6xl mx-auto",children:[e.jsxs("div",{className:"text-center mb-16",children:[e.jsx("p",{className:"text-xs font-semibold tracking-widest text-marca-principal uppercase mb-3",children:"Nuestros servicios"}),e.jsx("h2",{className:"text-3xl sm:text-4xl font-bold text-texto-titulo mb-4",children:"¿Qué hacemos?"}),e.jsx("p",{className:"text-texto-secundario max-w-xl mx-auto",children:"Tecnología inmersiva, conservación activa y educación científica para proteger la biodiversidad."})]}),e.jsx("div",{className:"space-y-20",children:i.map(a=>e.jsx(n,{bloque:a},a.id))})]})}),e.jsx("section",{id:"medios",className:"bg-fondo-superficie py-16 px-8 sm:px-12",children:e.jsxs("div",{className:"max-w-6xl mx-auto text-center",children:[e.jsx("p",{className:"text-xs font-semibold tracking-widest text-marca-principal uppercase mb-3",children:"Prensa"}),e.jsx("h2",{className:"text-3xl sm:text-4xl font-bold text-texto-titulo mb-4",children:"Nos han contado"}),e.jsx("p",{className:"text-texto-secundario max-w-xl mx-auto mb-10",children:"MUMA en los medios de comunicación."}),e.jsx("div",{className:"flex flex-wrap justify-center gap-4",children:r.map(a=>e.jsxs("a",{href:a.href,target:"_blank",rel:"noopener noreferrer",className:"px-6 py-3 border border-marca-principal/40 text-texto-secundario rounded-full text-sm font-medium hover:border-marca-principal hover:text-marca-principal transition-colors duration-200",children:[a.nombre," "]},a.nombre))})]})})]})}export{m as default};
